Use **`WebApplicationFactory<TEntryPoint>`** from `Microsoft.AspNetCore.Mvc.Testing`. It hosts your app in-memory and gives you an `HttpClient` — no ports, no real server.

### Setup

```bash
dotnet add tests/MyMcp.Tests package Microsoft.AspNetCore.Mvc.Testing
```

### Example test

```csharp
using Microsoft.AspNetCore.Mvc.Testing;
using System.Net.Http.Json;
using System.Text.Json;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.True(body.TryGetProperty("result", out var result));
        Assert.True(result.TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        // Initialize first
        await _client.PostAsJsonAsync("/mcp", new
        {
            jsonrpc = "2.0", id = 1, method = "initialize",
            @params = new {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        });

        var response = await _client.PostAsJsonAsync("/mcp", new
        {
            jsonrpc = "2.0", id = 2, method = "tools/list",
            @params = new { }
        });

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }
}
```

### Key points

| Concern | Approach |
|---|---|
| **No real server** | `WebApplicationFactory` hosts in-process via `TestServer` |
| **Override services** | Use `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap in mocks |
| **MCP session state** | If your server uses Streamable HTTP with session IDs, capture the `Mcp-Session-Id` header from the `initialize` response and send it on subsequent requests |
| **SSE transport** | Read the response stream with `ReadAsStreamAsync()` and parse `text/event-stream` lines |
| **`Program` visibility** | Add `<InternalsVisibleTo Include="YourTestProject" />` to the server's `.csproj`, or declare `public partial class Program { }` in `Program.cs` |

This gives you full protocol-level coverage (JSON-RPC framing, headers, status codes) with the speed of an in-process call.
